import React, { useState } from 'react';
import { useApp } from '../context/AppContext';
import { Users, ShieldOff, Shield, Plus, X } from 'lucide-react';

const ROLE_COLORS = {
  admin: { bg: '#fde8f0', text: '#c93261', label: 'Administrador' },
  cliente: { bg: '#eaf4fd', text: '#1a7abc', label: 'Cliente' },
  vendor: { bg: '#e8f8f0', text: '#1a9b56', label: 'Vendedor' }
};

export default function UsersAdmin() {
  const { users, toggleUserBlock, createUser, currentUser } = useApp();
  const [showForm, setShowForm] = useState(false);
  const [form, setForm] = useState({ name: '', email: '', password: '', role: 'cliente' });
  const [error, setError] = useState('');
  const [success, setSuccess] = useState('');

  const handleSubmit = (e) => {
    e.preventDefault();
    setError('');
    setSuccess('');

    if (!form.name.trim() || !form.email.trim() || !form.password.trim()) {
      setError('Por favor completa todos los campos');
      return;
    }

    if (!form.email.includes('@')) {
      setError('El correo no es válido');
      return;
    }

    const result = createUser(form.name, form.email, form.password, form.role);

    if (result.error) {
      setError(result.error);
    } else {
      setSuccess(`Usuario ${form.name} creado exitosamente como ${ROLE_COLORS[form.role].label}`);
      setForm({ name: '', email: '', password: '', role: 'cliente' });
      setShowForm(false);
      setTimeout(() => setSuccess(''), 3000);
    }
  };

  const getRoleColor = (role) => ROLE_COLORS[role] || ROLE_COLORS.cliente;

  return (
    <div className="p-6 bg-gray-50 min-h-screen">
      <div className="max-w-7xl mx-auto">
        {/* Header */}
        <div className="mb-6">
          <h1 className="text-3xl font-bold text-gray-800">Gestión de Usuarios</h1>
          <p className="text-gray-500">{users.length} usuarios registrados</p>
        </div>

        {/* Success/Error Messages */}
        {error && (
          <div className="mb-4 p-4 bg-red-100 text-red-700 rounded-lg flex justify-between items-center">
            <span>{error}</span>
            <button onClick={() => setError('')} className="text-red-700 hover:text-red-900">
              <X size={18} />
            </button>
          </div>
        )}
        {success && (
          <div className="mb-4 p-4 bg-green-100 text-green-700 rounded-lg flex justify-between items-center">
            <span>{success}</span>
            <button onClick={() => setSuccess('')} className="text-green-700 hover:text-green-900">
              <X size={18} />
            </button>
          </div>
        )}

        {/* Create User Button */}
        <div className="mb-6">
          <button
            onClick={() => setShowForm(!showForm)}
            className="flex items-center gap-2 bg-blue-600 text-white px-4 py-2 rounded-lg hover:bg-blue-700 font-medium"
          >
            <Plus size={20} /> Crear Usuario
          </button>
        </div>

        {/* Create User Form */}
        {showForm && (
          <div className="bg-white rounded-lg shadow p-6 mb-8">
            <div className="flex justify-between items-center mb-4">
              <h2 className="text-lg font-bold">Nuevo Usuario</h2>
              <button onClick={() => { setShowForm(false); setForm({ name: '', email: '', password: '', role: 'cliente' }); }} className="text-gray-400 hover:text-gray-600">
                <X size={20} />
              </button>
            </div>

            <form onSubmit={handleSubmit} className="grid grid-cols-2 gap-4">
              <input
                type="text"
                placeholder="Nombre completo"
                value={form.name}
                onChange={(e) => setForm({ ...form, name: e.target.value })}
                className="border rounded-lg px-3 py-2 text-sm"
              />
              <input
                type="email"
                placeholder="Correo electrónico"
                value={form.email}
                onChange={(e) => setForm({ ...form, email: e.target.value })}
                className="border rounded-lg px-3 py-2 text-sm"
              />
              <input
                type="password"
                placeholder="Contraseña"
                value={form.password}
                onChange={(e) => setForm({ ...form, password: e.target.value })}
                className="border rounded-lg px-3 py-2 text-sm"
              />
              <select
                value={form.role}
                onChange={(e) => setForm({ ...form, role: e.target.value })}
                className="border rounded-lg px-3 py-2 text-sm"
              >
                <option value="cliente">Cliente</option>
                <option value="vendor">Vendedor</option>
              </select>
              <button type="submit" className="col-span-2 bg-green-600 text-white py-2 rounded-lg hover:bg-green-700 font-medium">
                Crear Usuario
              </button>
            </form>
          </div>
        )}

        {/* Users Table */}
        <div className="bg-white rounded-lg shadow overflow-hidden">
          <div className="p-6 border-b border-gray-200">
            <h2 className="text-lg font-bold">Todos los Usuarios</h2>
          </div>

          {users.length === 0 ? (
            <div className="p-6 text-center text-gray-500">
              <Users size={40} className="mx-auto mb-2" />
              No hay usuarios registrados
            </div>
          ) : (
            <div className="overflow-x-auto">
              <table className="w-full">
                <thead className="bg-gray-50 border-b">
                  <tr>
                    <th className="px-6 py-3 text-left text-xs font-bold text-gray-700">Usuario</th>
                    <th className="px-6 py-3 text-left text-xs font-bold text-gray-700">Correo</th>
                    <th className="px-6 py-3 text-left text-xs font-bold text-gray-700">Rol</th>
                    <th className="px-6 py-3 text-left text-xs font-bold text-gray-700">Fecha de Registro</th>
                    <th className="px-6 py-3 text-left text-xs font-bold text-gray-700">Estado</th>
                    <th className="px-6 py-3 text-left text-xs font-bold text-gray-700">Acciones</th>
                  </tr>
                </thead>
                <tbody>
                  {users.map(u => {
                    const roleColor = getRoleColor(u.role);
                    return (
                      <tr key={u.id} className="border-b hover:bg-gray-50">
                        <td className="px-6 py-4">
                          <div className="flex items-center gap-3">
                            <div style={{ 
                              width: 34, 
                              height: 34, 
                              borderRadius: '50%', 
                              background: 'linear-gradient(135deg, var(--pink-300), var(--pink-500))', 
                              color: 'white', 
                              display: 'flex', 
                              alignItems: 'center', 
                              justifyContent: 'center', 
                              fontWeight: 700, 
                              fontSize: '0.9rem', 
                              flexShrink: 0 
                            }}>
                              {u.name[0]}
                            </div>
                            <span className="font-medium text-gray-800">{u.name}</span>
                          </div>
                        </td>
                        <td className="px-6 py-4 text-sm text-gray-600">{u.email}</td>
                        <td className="px-6 py-4">
                          <span className="px-3 py-1 rounded-full text-xs font-medium" style={{ backgroundColor: roleColor.bg, color: roleColor.text }}>
                            {roleColor.label}
                          </span>
                        </td>
                        <td className="px-6 py-4 text-sm text-gray-600">{u.joinDate}</td>
                        <td className="px-6 py-4">
                          <span className={`px-3 py-1 rounded-full text-xs font-medium ${
                            u.status === 'activo' ? 'bg-green-100 text-green-800' : 'bg-red-100 text-red-800'
                          }`}>
                            {u.status}
                          </span>
                        </td>
                        <td className="px-6 py-4">
                          {u.id !== currentUser?.id && (
                            <button
                              className={`flex items-center gap-2 px-3 py-1 rounded text-sm font-medium ${
                                u.status === 'activo' 
                                  ? 'bg-red-100 text-red-700 hover:bg-red-200' 
                                  : 'bg-green-100 text-green-700 hover:bg-green-200'
                              }`}
                              onClick={() => toggleUserBlock(u.id)}
                            >
                              {u.status === 'activo' ? <><ShieldOff size={13} /> Bloquear</> : <><Shield size={13} /> Desbloquear</>}
                            </button>
                          )}
                        </td>
                      </tr>
                    );
                  })}
                </tbody>
              </table>
            </div>
          )}
        </div>

        {/* User Statistics */}
        <div className="grid grid-cols-1 md:grid-cols-3 gap-4 mt-8">
          {[
            { label: 'Clientes', count: users.filter(u => u.role === 'cliente').length, color: '#eaf4fd', iconColor: '#1a7abc' },
            { label: 'Vendedores', count: users.filter(u => u.role === 'vendor').length, color: '#e8f8f0', iconColor: '#1a9b56' },
            { label: 'Bloqueados', count: users.filter(u => u.status === 'bloqueado').length, color: '#ffe8e8', iconColor: '#c92a2a' }
          ].map((stat, i) => (
            <div key={i} className="bg-white rounded-lg shadow p-6">
              <div className="flex items-center justify-between">
                <div>
                  <p className="text-sm text-gray-500 mb-2">{stat.label}</p>
                  <p className="text-2xl font-bold text-gray-800">{stat.count}</p>
                </div>
                <div style={{ backgroundColor: stat.color }} className="p-3 rounded-lg">
                  <Users size={24} color={stat.iconColor} />
                </div>
              </div>
            </div>
          ))}
        </div>
      </div>
    </div>
  );
}
